import{_ as s,o as e,c as a,a2 as n}from"./chunks/framework.B72_uj9U.js";const y=JSON.parse('{"title":"Goose — Unique Patterns & Key Differentiators","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/goose/unique-patterns.md","filePath":"research/agents/goose/unique-patterns.md"}'),o={name:"research/agents/goose/unique-patterns.md"};function l(i,t,r,p,c,d){return e(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="goose-—-unique-patterns-key-differentiators" tabindex="-1">Goose — Unique Patterns &amp; Key Differentiators <a class="header-anchor" href="#goose-—-unique-patterns-key-differentiators" aria-label="Permalink to &quot;Goose — Unique Patterns &amp; Key Differentiators&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Goose makes several distinctive architectural choices that set it apart from other coding agents. The most significant is its wholesale adoption of MCP (Model Context Protocol) as the universal extension interface, combined with Block&#39;s enterprise-oriented perspective on agent safety and deployment.</p><h2 id="_1-mcp-as-the-universal-extension-interface" tabindex="-1">1. MCP as the Universal Extension Interface <a class="header-anchor" href="#_1-mcp-as-the-universal-extension-interface" aria-label="Permalink to &quot;1. MCP as the Universal Extension Interface&quot;">​</a></h2><h3 id="the-pattern" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>While other agents (Claude Code, Codex CLI, Aider) build their tool systems as internal abstractions with MCP as an optional add-on, <strong>Goose builds everything on MCP from the ground up</strong>. There is no separate &quot;built-in tool&quot; layer — file editing, shell execution, code analysis, and memory are all MCP servers.</p><h3 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h3><p>Every tool interaction flows through <code>McpClientTrait</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">async_trait</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> trait</span><span style="color:#F9E2AF;font-style:italic;"> McpClientTrait</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Send</span><span style="color:#94E2D5;"> +</span><span style="color:#F9E2AF;font-style:italic;"> Sync</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> list_tools</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ListToolsResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> call_tool</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> ...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">CallToolResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> list_resources</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ListResourcesResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> read_resource</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ReadResourceResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> list_prompts</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ListPromptsResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> get_prompt</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">...</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">GetPromptResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> subscribe</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;"> mpsc</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Receiver</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">ServerNotification</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">    async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> get_moim</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> session_id</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This means:</p><ul><li>Built-in developer tools (shell, edit, write, tree) implement <code>McpClientTrait</code></li><li>Builtin MCP servers (computer controller, memory) run over DuplexStream</li><li>External extensions (GitHub, Postgres) connect over stdio or HTTP</li><li>All use the identical dispatch path in the agent loop</li></ul><h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><ol><li><strong>Ecosystem leverage</strong>: Any MCP server works with Goose immediately. The MCP ecosystem is growing rapidly.</li><li><strong>Consistent security</strong>: The same inspection pipeline (security → adversary → permission → repetition) applies to ALL tools, regardless of origin.</li><li><strong>Extension composability</strong>: Extensions can be mixed, matched, enabled/disabled without changing agent logic.</li><li><strong>Portability</strong>: Goose&#39;s built-in MCP servers can run standalone with other MCP clients.</li></ol><h3 id="trade-offs" tabindex="-1">Trade-offs <a class="header-anchor" href="#trade-offs" aria-label="Permalink to &quot;Trade-offs&quot;">​</a></h3><ul><li><strong>Performance overhead</strong>: In-process tools go through MCP serialization even for simple operations. Platform extensions mitigate this by implementing <code>McpClientTrait</code> directly without transport.</li><li><strong>Complexity</strong>: The 7 transport types (Platform, Builtin, Stdio, StreamableHttp, InlinePython, Frontend, SSE) add complexity compared to a simple function-call interface.</li></ul><h2 id="_2-multi-tier-extension-architecture" tabindex="-1">2. Multi-Tier Extension Architecture <a class="header-anchor" href="#_2-multi-tier-extension-architecture" aria-label="Permalink to &quot;2. Multi-Tier Extension Architecture&quot;">​</a></h2><h3 id="the-pattern-1" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-1" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Goose doesn&#39;t have a single extension type — it has a tiered hierarchy optimized for different use cases:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Type</th><th>Transport</th><th>Access Level</th><th>Example</th></tr></thead><tbody><tr><td>1</td><td>Platform</td><td>Direct (in-process)</td><td>Full agent access</td><td>developer, analyze, summon</td></tr><tr><td>2</td><td>Builtin</td><td>DuplexStream (in-process MCP)</td><td>Standard MCP</td><td>computercontroller, memory</td></tr><tr><td>3</td><td>Stdio</td><td>Child process stdin/stdout</td><td>Standard MCP</td><td>npm/uvx packages</td></tr><tr><td>4</td><td>StreamableHttp</td><td>HTTP</td><td>Standard MCP</td><td>Remote services</td></tr><tr><td>5</td><td>InlinePython</td><td>Child process (uvx)</td><td>Standard MCP</td><td>User Python scripts</td></tr><tr><td>6</td><td>Frontend</td><td>UI channel</td><td>UI-only</td><td>Interactive widgets</td></tr></tbody></table><h3 id="why-this-matters-1" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-1" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><ul><li><strong>Platform extensions</strong> get access to <code>PlatformExtensionContext</code>, enabling features like the Extension Manager (which can add/remove other extensions at runtime) and Summon (which can spawn subagents).</li><li><strong>Builtin extensions</strong> benefit from in-process efficiency while maintaining MCP protocol compliance.</li><li><strong>Stdio/HTTP extensions</strong> provide the plug-and-play ecosystem experience.</li><li><strong>InlinePython</strong> enables rapid prototyping of extensions without publishing packages.</li></ul><h2 id="_3-moim-model-oriented-information-management" tabindex="-1">3. MOIM (Model-Oriented Information Management) <a class="header-anchor" href="#_3-moim-model-oriented-information-management" aria-label="Permalink to &quot;3. MOIM (Model-Oriented Information Management)&quot;">​</a></h2><h3 id="the-pattern-2" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-2" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>MOIM is a per-turn context injection mechanism. Before each LLM call, Goose queries all extensions for dynamic context via <code>get_moim()</code>, then injects it into the conversation.</p><h3 id="implementation-1" tabindex="-1">Implementation <a class="header-anchor" href="#implementation-1" aria-label="Permalink to &quot;Implementation&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Each turn, before calling the LLM:</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> conversation_with_moim </span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;"> super</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">moim</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">inject_moim</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#94E2D5;">    &amp;</span><span style="color:#CDD6F4;">conversation</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">extension_manager</span></span>
<span class="line"><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#9399B2;">;</span></span></code></pre></div><p>Extensions implement:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> get_moim</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> session_id</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">;</span></span></code></pre></div><h3 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h3><ul><li><strong>Top of Mind</strong> extension: Users set persistent instructions via environment variables that are injected every turn, ensuring the agent never &quot;forgets&quot; key requirements.</li><li>Extensions can dynamically adjust their guidance based on session state.</li></ul><h3 id="why-this-matters-2" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-2" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>This is a clean solution to the &quot;context drift&quot; problem — where important instructions get buried in long conversations. Instead of relying on the LLM to remember instructions from the beginning, MOIM re-injects them every turn.</p><h2 id="_4-background-tool-pair-summarization" tabindex="-1">4. Background Tool-Pair Summarization <a class="header-anchor" href="#_4-background-tool-pair-summarization" aria-label="Permalink to &quot;4. Background Tool-Pair Summarization&quot;">​</a></h2><h3 id="the-pattern-3" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-3" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Most agents handle context overflow reactively (compact when you hit the limit). Goose additionally runs a <strong>proactive background task</strong> each turn that summarizes old tool request/response pairs.</p><h3 id="implementation-2" tabindex="-1">Implementation <a class="header-anchor" href="#implementation-2" aria-label="Permalink to &quot;Implementation&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Runs as a background tokio task each turn</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> maybe_summarize_tool_pairs</span><span style="color:#9399B2;">(</span></span>
<span class="line"><span style="color:#EBA0AC;">    provider</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#F9E2AF;font-style:italic;"> Provider</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    session_id</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    conversation</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">Conversation</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#EBA0AC;">    tool_call_cut_off</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> usize</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> JoinHandle</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Vec</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">usize</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Message</span><span style="color:#9399B2;">)</span><span style="color:#89DCEB;">&gt;&gt;</span></span></code></pre></div><p>Old tool pairs are:</p><ol><li>Summarized by the LLM into concise descriptions</li><li>Marked as <code>agent_invisible</code> (kept for UI, hidden from LLM)</li><li>Replaced with summary messages</li></ol><h3 id="why-this-matters-3" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-3" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>Tool results are often the largest context consumers (think: full file contents, command outputs, search results). By progressively summarizing them, Goose maintains a much longer effective conversation history than agents that only compact reactively.</p><h2 id="_5-recipe-system-with-retry-logic" tabindex="-1">5. Recipe System with Retry Logic <a class="header-anchor" href="#_5-recipe-system-with-retry-logic" aria-label="Permalink to &quot;5. Recipe System with Retry Logic&quot;">​</a></h2><h3 id="the-pattern-4" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-4" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Goose supports &quot;recipes&quot; — automated task templates with success criteria, retry logic, and conversation reset. This enables unattended task execution.</p><h3 id="implementation-3" tabindex="-1">Implementation <a class="header-anchor" href="#implementation-3" aria-label="Permalink to &quot;Implementation&quot;">​</a></h3><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> RetryManager</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">    attempts</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Mutex</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">u32</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">    repetition_inspector</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Arc</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Mutex</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Option</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">RepetitionInspector</span><span style="color:#89DCEB;">&gt;&gt;&gt;&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The retry flow:</p><ol><li>Execute task according to recipe instructions</li><li>Run success checks (shell commands with timeouts)</li><li>If all pass → done</li><li>If any fail and attempts &lt; max_retries: <ul><li>Execute <code>on_failure</code> command if configured</li><li><strong>Reset conversation</strong> to initial state</li><li>Increment attempts</li><li>Retry from scratch</li></ul></li></ol><h3 id="why-this-matters-4" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-4" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>Conversation reset is the key innovation. Instead of continuing a failing conversation (which often leads to deeper holes), Goose clears the slate and starts fresh. This is similar to how a human developer might &quot;start over&quot; when debugging gets too tangled.</p><p>This also enables CI/CD usage: Goose can be pointed at a task, left to retry autonomously, and report success/failure.</p><h2 id="_6-subagent-delegation-summon" tabindex="-1">6. Subagent Delegation (Summon) <a class="header-anchor" href="#_6-subagent-delegation-summon" aria-label="Permalink to &quot;6. Subagent Delegation (Summon)&quot;">​</a></h2><h3 id="the-pattern-5" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-5" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>The Summon extension enables the main agent to delegate tasks to subagents with isolated contexts. Each subagent can have its own set of extensions and instructions.</p><h3 id="why-this-matters-5" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-5" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><ul><li><strong>Context isolation</strong>: Complex sub-tasks don&#39;t pollute the main conversation</li><li><strong>Extension scoping</strong>: A subagent for database work might only have the PostgreSQL extension</li><li><strong>Skill/recipe loading</strong>: Predefined task templates (called &quot;skills&quot;) can be loaded on demand</li><li><strong>Parallelism potential</strong>: Multiple subagents could work on different aspects of a task</li></ul><h2 id="_7-enterprise-permission-safety-model" tabindex="-1">7. Enterprise Permission &amp; Safety Model <a class="header-anchor" href="#_7-enterprise-permission-safety-model" aria-label="Permalink to &quot;7. Enterprise Permission &amp; Safety Model&quot;">​</a></h2><h3 id="the-pattern-6" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-6" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Goose implements a 4-level permission system designed for enterprise deployment:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Autonomous → Smart Approval → Manual Approval → Chat Only</span></span>
<span class="line"><span>(most permissive)                    (most restrictive)</span></span></code></pre></div><p>Combined with:</p><ul><li><strong>Per-tool permissions</strong>: Fine-grained allow/ask/deny per tool</li><li><strong><code>.gooseignore</code> files</strong>: Restrict which files/directories Goose can access</li><li><strong>4-inspector security pipeline</strong>: Runs on every tool call</li><li><strong>Malware detection</strong>: Checks external extensions against known malware databases</li><li><strong>Custom distributions</strong>: Organizations can build branded Goose distributions with preconfigured providers, extensions, and security settings</li></ul><h3 id="why-this-matters-6" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-6" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>Block (Square) is a financial technology company. Their enterprise perspective infuses Goose with security considerations that open-source-first agents often lack:</p><ol><li><strong>Audit trail</strong>: All tool calls are logged with inspection results</li><li><strong>Gradual trust</strong>: Users can start in Manual Approval mode and relax as they gain confidence</li><li><strong>Mid-session switching</strong>: Permission mode can change mid-conversation (<code>/mode approve</code>)</li><li><strong>Organizational control</strong>: Custom distributions enable IT to pre-configure safety settings</li></ol><h2 id="_8-multi-provider-with-toolshim" tabindex="-1">8. Multi-Provider with Toolshim <a class="header-anchor" href="#_8-multi-provider-with-toolshim" aria-label="Permalink to &quot;8. Multi-Provider with Toolshim&quot;">​</a></h2><h3 id="the-pattern-7" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-7" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Goose supports 30+ LLM providers. For models that don&#39;t natively support tool calling (e.g., some Ollama models), it uses a &quot;toolshim&quot;:</p><ol><li>Tool definitions are converted to text instructions in the system prompt</li><li>The LLM&#39;s text output is post-processed to extract JSON tool calls from code blocks</li><li>These are then dispatched through the normal tool pipeline</li></ol><h3 id="why-this-matters-7" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-7" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>This makes Goose truly provider-agnostic. Users can run local models via Ollama or LM Studio and still get tool-calling functionality, even if the model doesn&#39;t natively support function calling.</p><h2 id="_9-agent-communication-protocol-acp" tabindex="-1">9. Agent Communication Protocol (ACP) <a class="header-anchor" href="#_9-agent-communication-protocol-acp" aria-label="Permalink to &quot;9. Agent Communication Protocol (ACP)&quot;">​</a></h2><h3 id="the-pattern-8" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-8" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Goose supports ACP (Agent Communication Protocol), enabling it to use other agents as providers:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// ACP providers in crates/goose-acp/</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#F9E2AF;font-style:italic;"> Claude</span><span style="color:#F9E2AF;font-style:italic;"> Code</span><span style="color:#FAB387;"> ACP</span><span style="color:#CDD6F4;"> → uses </span><span style="color:#F9E2AF;font-style:italic;">Claude</span><span style="color:#F9E2AF;font-style:italic;"> Code</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> the </span><span style="color:#A6E3A1;">&quot;LLM&quot;</span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#F9E2AF;font-style:italic;"> Codex</span><span style="color:#FAB387;"> ACP</span><span style="color:#CDD6F4;"> → uses </span><span style="color:#F9E2AF;font-style:italic;">OpenAI</span><span style="color:#F9E2AF;font-style:italic;"> Codex</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> the </span><span style="color:#A6E3A1;">&quot;LLM&quot;</span><span style="color:#CDD6F4;">  </span></span>
<span class="line"><span style="color:#94E2D5;">-</span><span style="color:#F9E2AF;font-style:italic;"> Gemini</span><span style="color:#FAB387;"> ACP</span><span style="color:#CDD6F4;"> → uses </span><span style="color:#F9E2AF;font-style:italic;">Gemini</span><span style="color:#FAB387;"> CLI</span><span style="color:#CBA6F7;"> as</span><span style="color:#CDD6F4;"> the </span><span style="color:#A6E3A1;">&quot;LLM&quot;</span></span></code></pre></div><p>ACP providers pass Goose&#39;s extensions through to the underlying agent as MCP servers.</p><h3 id="why-this-matters-8" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-8" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>This creates an &quot;agent-of-agents&quot; pattern:</p><ul><li>Goose provides the extension/tool ecosystem</li><li>The underlying agent (Claude Code, Codex, Gemini) provides the reasoning</li><li>Extensions are shared, creating a unified experience regardless of which agent is doing the reasoning</li></ul><h2 id="_10-deep-link-extension-installation" tabindex="-1">10. Deep Link Extension Installation <a class="header-anchor" href="#_10-deep-link-extension-installation" aria-label="Permalink to &quot;10. Deep Link Extension Installation&quot;">​</a></h2><h3 id="the-pattern-9" tabindex="-1">The Pattern <a class="header-anchor" href="#the-pattern-9" aria-label="Permalink to &quot;The Pattern&quot;">​</a></h3><p>Extensions can be installed via URL deep links:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>goose://extension?cmd=npx&amp;arg=-y&amp;arg=%40modelcontextprotocol/server-github&amp;id=github&amp;name=GitHub</span></span></code></pre></div><h3 id="why-this-matters-9" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters-9" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>This enables:</p><ul><li><strong>One-click installation</strong> from documentation or web pages</li><li><strong>Shareable configurations</strong> via URLs</li><li><strong>Extension directories</strong> that provide install links</li><li><strong>Onboarding flows</strong> that set up entire development environments</li></ul><h2 id="comparison-matrix" tabindex="-1">Comparison Matrix <a class="header-anchor" href="#comparison-matrix" aria-label="Permalink to &quot;Comparison Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>Goose</th><th>Claude Code</th><th>Codex CLI</th><th>Aider</th></tr></thead><tbody><tr><td>MCP-native tools</td><td>✅ Everything</td><td>⚠️ Add-on</td><td>⚠️ Limited</td><td>❌ No</td></tr><tr><td>Multi-tier extensions</td><td>✅ 7 types</td><td>❌ 1 type</td><td>❌ 1 type</td><td>❌ N/A</td></tr><tr><td>MOIM (per-turn injection)</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Background summarization</td><td>✅ Tool-pairs</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Recipe + retry</td><td>✅ With reset</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Subagent delegation</td><td>✅ Summon</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Enterprise permissions</td><td>✅ 4 modes</td><td>⚠️ Basic</td><td>⚠️ Basic</td><td>❌</td></tr><tr><td>Provider agnostic</td><td>✅ 30+</td><td>❌ Anthropic only</td><td>❌ OpenAI only</td><td>✅ Many</td></tr><tr><td>Agent-as-provider (ACP)</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Deep link install</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>Desktop app</td><td>✅ Electron</td><td>❌ CLI only</td><td>❌ CLI only</td><td>❌ CLI only</td></tr></tbody></table><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Goose&#39;s key differentiator is its <strong>MCP-first architecture</strong>. While other agents treat MCP as an integration layer bolted onto existing tool systems, Goose makes MCP the foundation. This creates a uniquely extensible and composable agent, at the cost of additional architectural complexity. Block&#39;s enterprise background adds a layer of safety and deployment sophistication that few open-source agents match.</p>`,90)])])}const u=s(o,[["render",l]]);export{y as __pageData,u as default};
